# Merge wa.* translation namespace into all locale files.
# Idempotent: removes existing "wa": {...} block (top-level) before inserting fresh.

$ErrorActionPreference = 'Stop'
$root = Split-Path -Parent $PSScriptRoot
$localesDir = Join-Path $root 'locales'
$enc = [System.Text.UTF8Encoding]::new($false)

function Build-WaBlock {
  param([hashtable]$wa)
  return ($wa | ConvertTo-Json -Depth 12)
}

function Remove-ExistingWa {
  param([string]$text)
  # Find the "wa": { occurrence and remove balanced block + leading comma.
  $idx = $text.IndexOf('"wa":')
  if ($idx -lt 0) { return $text }
  # Find opening brace
  $openIdx = $text.IndexOf('{', $idx)
  if ($openIdx -lt 0) { return $text }
  $depth = 0
  $i = $openIdx
  while ($i -lt $text.Length) {
    $c = $text[$i]
    if ($c -eq '{') { $depth++ }
    elseif ($c -eq '}') {
      $depth--
      if ($depth -eq 0) { break }
    }
    $i++
  }
  if ($depth -ne 0) { return $text }
  $endIdx = $i  # index of matching closing brace
  # Walk back from $idx to find leading comma
  $startIdx = $idx
  $j = $idx - 1
  while ($j -ge 0 -and ($text[$j] -eq ' ' -or $text[$j] -eq "`r" -or $text[$j] -eq "`n" -or $text[$j] -eq "`t")) { $j-- }
  if ($j -ge 0 -and $text[$j] -eq ',') { $startIdx = $j }
  return $text.Substring(0, $startIdx) + $text.Substring($endIdx + 1)
}

function Insert-Wa {
  param([string]$text, [string]$waJson)
  # waJson is a full {...} object. Insert as last property of root object.
  $lastBrace = $text.LastIndexOf('}')
  if ($lastBrace -lt 0) { throw 'No closing brace found' }
  # Walk back from $lastBrace to find last non-whitespace char
  $j = $lastBrace - 1
  while ($j -ge 0 -and ($text[$j] -eq ' ' -or $text[$j] -eq "`r" -or $text[$j] -eq "`n" -or $text[$j] -eq "`t")) { $j-- }
  $needsComma = $true
  if ($j -ge 0 -and ($text[$j] -eq '{' -or $text[$j] -eq ',')) { $needsComma = $false }
  $sep = if ($needsComma) { ",`r`n  " } else { "`r`n  " }
  # Strip outer braces from waJson and indent
  $inner = $waJson.Trim()
  if ($inner.StartsWith('{')) { $inner = $inner.Substring(1) }
  if ($inner.EndsWith('}'))   { $inner = $inner.Substring(0, $inner.Length - 1) }
  $inner = $inner.Trim()
  $insert = $sep + '"wa": {' + "`r`n    " + $inner + "`r`n  }"
  return $text.Substring(0, $j + 1) + $insert + "`r`n" + $text.Substring($lastBrace)
}

