# Merge $extraPacks into $packs (adds new namespaces alongside existing)
foreach ($key in $extraPacks.Keys) {
  if (-not $packs.ContainsKey($key)) { continue }
  foreach ($ns in $extraPacks[$key].Keys) {
    $packs[$key][$ns] = $extraPacks[$key][$ns]
  }
}

# ============================================================
# MERGE
# ============================================================
foreach ($key in $packs.Keys) {
  $file = Join-Path $localesDir "$key.json"
  if (-not (Test-Path $file)) {
    Write-Host "SKIP $key — file not found: $file" -ForegroundColor Yellow
    continue
  }
  $text = [System.IO.File]::ReadAllText($file, $enc)
  $cleaned = Remove-ExistingWa -text $text
  $waJson = Build-WaBlock -wa $packs[$key]
  $merged = Insert-Wa -text $cleaned -waJson $waJson
  [System.IO.File]::WriteAllText($file, $merged, $enc)
  Write-Host "OK   $key" -ForegroundColor Green
}

Write-Host ""
Write-Host "Done. Run: shopify theme push --only locales/" -ForegroundColor Cyan
